  1→<!DOCTYPE html>
  2→<html lang="en">
  3→<head>
  4→<meta charset="UTF-8">
  5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
  6→<title>Chess Demo</title>
  7→<style>
  8→  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  9→
 10→  body {
 11→    min-height: 100vh;
 12→    display: flex;
 13→    flex-direction: column;
 14→    justify-content: center;
 15→    align-items: center;
 16→    background: #1a1a2e;
 17→    font-family: system-ui, -apple-system, sans-serif;
 18→    padding: 1rem;
 19→  }
 20→
 21→  .game-wrapper {
 22→    display: flex;
 23→    flex-direction: column;
 24→    align-items: center;
 25→    gap: 0.75rem;
 26→    width: min(90vw, 90vh, 600px);
 27→  }
 28→
 29→  /* Status bar */
 30→  .status-bar {
 31→    width: 100%;
 32→    background: #16213e;
 33→    border-radius: 8px;
 34→    padding: 0.75rem 1.25rem;
 35→    display: flex;
 36→    justify-content: space-between;
 37→    align-items: center;
 38→    box-shadow: 0 2px 12px rgba(0,0,0,.3);
 39→  }
 40→
 41→  .status-text {
 42→    color: #e0e0e8;
 43→    font-size: 1.05rem;
 44→    font-weight: 600;
 45→  }
 46→
 47→  .status-text .check-warning {
 48→    color: #e74c3c;
 49→    font-weight: 700;
 50→  }
 51→
 52→  .status-text .result {
 53→    color: #f6e96b;
 54→  }
 55→
 56→  .turn-dot {
 57→    display: inline-block;
 58→    width: 12px;
 59→    height: 12px;
 60→    border-radius: 50%;
 61→    margin-right: 0.5rem;
