 63→    border: 2px solid #555;
 64→  }
 65→
 66→  .turn-dot.white { background: #fff; }
 67→  .turn-dot.black { background: #222; }
 68→
 69→  .new-game-btn {
 70→    background: #0f3460;
 71→    color: #e0e0e8;
 72→    border: 1px solid #1a5276;
 73→    border-radius: 6px;
 74→    padding: 0.45rem 1rem;
