 81→
 82→  .new-game-btn:hover { background: #1a5276; }
 83→  .new-game-btn:active { transform: scale(0.97); }
 84→
 85→  /* Captured pieces */
 86→  .captured-row {
 87→    width: 100%;
 88→    background: #16213e;
 89→    border-radius: 6px;
 90→    padding: 0.4rem 0.75rem;
 91→    min-height: 2.2rem;
 92→    display: flex;
 93→    align-items: center;
 94→    gap: 0.15rem;
 95→    box-shadow: 0 1px 6px rgba(0,0,0,.2);
 96→  }
 97→
 98→  .captured-label {
 99→    color: #666;
100→    font-size: 0.75rem;
101→    font-weight: 600;
102→    text-transform: uppercase;
103→    letter-spacing: 0.04em;
104→    margin-right: 0.4rem;
105→    flex-shrink: 0;
106→  }
107→
108→  .captured-pieces {
109→    display: flex;
110→    flex-wrap: wrap;
111→    gap: 0.1rem;
112→    font-size: 1.3rem;
113→    line-height: 1;
