115→
116→  /* Board */
117→  .board-container {
118→    display: inline-grid;
119→    grid-template-columns: 2rem repeat(8, 1fr);
120→    grid-template-rows: repeat(8, 1fr) 2rem;
121→    width: 100%;
122→    aspect-ratio: 1;
123→    border: 4px solid #16213e;
