128→
129→  .rank-label {
130→    display: flex;
131→    align-items: center;
132→    justify-content: center;
133→    background: #16213e;
134→    color: #a0a0b0;
135→    font-size: 0.85rem;
136→    font-weight: 600;
137→    width: 2rem;
138→  }
139→
140→  .file-label {
141→    display: flex;
142→    align-items: center;
143→    justify-content: center;
144→    background: #16213e;
145→    color: #a0a0b0;
146→    font-size: 0.85rem;
147→    font-weight: 600;
148→    height: 2rem;
