150→
151→  .corner {
152→    background: #16213e;
153→  }
154→
155→  .square {
156→    display: flex;
157→    align-items: center;
158→    justify-content: center;
159→    font-size: clamp(1.5rem, 5vw, 3.2rem);
160→    cursor: pointer;
161→    user-select: none;
162→    transition: background-color 0.15s;
163→    aspect-ratio: 1;
164→    position: relative;
165→  }
166→
167→  .square .piece {
168→    transition: opacity 0.15s ease;
169→  }
170→
171→  .square.light { background: #e8dcc8; }
172→  .square.dark  { background: #7b6b4f; }
173→  .square:hover { filter: brightness(1.12); }
174→
175→  .square.selected { background: #f6e96b !important; }
176→  .square.valid-move::after {
177→    content: '';
178→    position: absolute;
179→    width: 30%;
180→    height: 30%;
181→    background: rgba(0, 0, 0, 0.25);
182→    border-radius: 50%;
183→    pointer-events: none;
184→  }
185→  .square.valid-move.has-enemy::after {
186→    width: 85%;
187→    height: 85%;
188→    background: transparent;
189→    border: 5px solid rgba(0, 0, 0, 0.25);
190→    border-radius: 50%;
191→  }
192→
193→  .square.last-move {
194→    background: rgba(246, 233, 107, 0.35) !important;
195→  }
196→
197→  .square.in-check {
198→    background: #e74c3c !important;
199→    box-shadow: inset 0 0 12px rgba(0,0,0,.4);
200→  }
201→
202→  /* Move animation */
203→  @keyframes pieceAppear {
204→    from { transform: scale(0.7); opacity: 0.4; }
205→    to { transform: scale(1); opacity: 1; }
206→  }
207→
208→  .square.just-moved .piece {
209→    animation: pieceAppear 0.2s ease-out;
210→  }
211→
212→  /* Promotion overlay */
213→  .promotion-overlay {
214→    display: none;
215→    position: fixed;
216→    inset: 0;
217→    background: rgba(0, 0, 0, 0.6);
218→    z-index: 100;
219→    justify-content: center;
220→    align-items: center;
221→  }
222→  .promotion-overlay.active { display: flex; }
223→  .promotion-dialog {
224→    background: #16213e;
225→    border-radius: 12px;
226→    padding: 1.5rem;
227→    text-align: center;
228→    box-shadow: 0 8px 32px rgba(0,0,0,.5);
229→  }
230→  .promotion-dialog h3 {
231→    color: #a0a0b0;
232→    margin-bottom: 1rem;
233→    font-size: 1.1rem;
234→  }
235→  .promotion-choices {
236→    display: flex;
237→    gap: 0.5rem;
238→  }
239→  .promotion-choices button {
240→    font-size: 2.5rem;
241→    width: 4rem;
242→    height: 4rem;
243→    border: 2px solid #a0a0b0;
244→    border-radius: 8px;
245→    background: #e8dcc8;
246→    cursor: pointer;
247→    transition: transform 0.1s, border-color 0.15s;
248→  }
249→  .promotion-choices button:hover {
250→    transform: scale(1.1);
251→    border-color: #f6e96b;
252→  }
253→
254→  @media (max-width: 500px) {
255→    .status-bar { padding: 0.5rem 0.75rem; }
256→    .status-text { font-size: 0.9rem; }
257→    .new-game-btn { padding: 0.35rem 0.7rem; font-size: 0.8rem; }
258→    .rank-label, .file-label { font-size: 0.7rem; }
259→    .rank-label { width: 1.5rem; }
260→    .board-container { grid-template-columns: 1.5rem repeat(8, 1fr); }
261→  }
262→</style>
263→</head>
264→<body>
265→
266→<div class="game-wrapper">
267→  <div class="status-bar">
268→    <div class="status-text" id="status"><span class="turn-dot white"></span>White's turn</div>
269→    <button class="new-game-btn" id="newGameBtn">New Game</button>
270→  </div>
271→
272→  <div class="captured-row" id="capturedBlack">
273→    <span class="captured-label">Black:</span>
274→    <div class="captured-pieces" id="capturedBlackPieces"></div>
275→  </div>
276→
277→  <div class="board-container" id="board"></div>
278→
279→  <div class="captured-row" id="capturedWhite">
280→    <span class="captured-label">White:</span>
281→    <div class="captured-pieces" id="capturedWhitePieces"></div>
282→  </div>
283→</div>
284→
285→<div class="promotion-overlay" id="promotion-overlay">
286→  <div class="promotion-dialog">
287→    <h3>Promote pawn to:</h3>
288→    <div class="promotion-choices" id="promotion-choices"></div>
289→  </div>
290→</div>
291→
292→<script>
293→const PIECES = {
294→  K: { type: 'king',   color: 'white', symbol: '\u2654' },
295→  Q: { type: 'queen',  color: 'white', symbol: '\u2655' },
296→  R: { type: 'rook',   color: 'white', symbol: '\u2656' },
297→  B: { type: 'bishop', color: 'white', symbol: '\u2657' },
298→  N: { type: 'knight', color: 'white', symbol: '\u2658' },
299→  P: { type: 'pawn',   color: 'white', symbol: '\u2659' },
300→  k: { type: 'king',   color: 'black', symbol: '\u265A' },
301→  q: { type: 'queen',  color: 'black', symbol: '\u265B' },
302→  r: { type: 'rook',   color: 'black', symbol: '\u265C' },
303→  b: { type: 'bishop', color: 'black', symbol: '\u265D' },
304→  n: { type: 'knight', color: 'black', symbol: '\u265E' },
305→  p: { type: 'pawn',   color: 'black', symbol: '\u265F' },
306→};
307→
308→const PIECE_VALUE = { pawn: 1, knight: 3, bishop: 3, rook: 5, queen: 9, king: 0 };
309→
310→function makePiece(key) {
311→  if (!key) return null;
312→  const p = PIECES[key];
313→  return { type: p.type, color: p.color, symbol: p.symbol };
314→}
315→
316→const INITIAL = [
317→  ['r','n','b','q','k','b','n','r'],
318→  ['p','p','p','p','p','p','p','p'],
319→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
320→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
321→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
322→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
323→  ['P','P','P','P','P','P','P','P'],
324→  ['R','N','B','Q','K','B','N','R'],
325→];
326→
327→const FILES = ['a','b','c','d','e','f','g','h'];
328→const container = document.getElementById('board');
329→const statusEl = document.getElementById('status');
330→const capturedWhiteEl = document.getElementById('capturedWhitePieces');
331→const capturedBlackEl = document.getElementById('capturedBlackPieces');
332→
333→let boardState;
334→let currentTurn;
335→let selectedSquare;
336→let validMoves;
337→let gameOver;
338→let capturedWhite; // pieces captured BY white (black pieces)
339→let capturedBlack; // pieces captured BY black (white pieces)
340→let lastMove;      // { piece, fromRow, fromCol, toRow, toCol }
341→let hasMoved;      // track king/rook moves for castling
342→let pendingPromotion; // { row, col } when awaiting promotion choice
343→
344→function initGameState() {
345→  boardState = INITIAL.map(row => row.map(makePiece));
346→  currentTurn = 'white';
347→  selectedSquare = null;
348→  validMoves = [];
349→  gameOver = false;
350→  capturedWhite = [];
351→  capturedBlack = [];
352→  lastMove = null;
353→  hasMoved = { whiteKing: false, whiteRookA: false, whiteRookH: false, blackKing: false, blackRookA: false, blackRookH: false };
354→  pendingPromotion = null;
355→}
356→
357→function inBounds(r, c) {
358→  return r >= 0 && r < 8 && c >= 0 && c < 8;
359→}
360→
361→function slidingMoves(row, col, directions) {
362→  const piece = boardState[row][col];
363→  const moves = [];
364→  for (const [dr, dc] of directions) {
365→    let r = row + dr, c = col + dc;
366→    while (inBounds(r, c)) {
367→      const target = boardState[r][c];
368→      if (!target) {
369→        moves.push({ row: r, col: c });
370→      } else {
371→        if (target.color !== piece.color) moves.push({ row: r, col: c });
372→        break;
373→      }
374→      r += dr;
375→      c += dc;
376→    }
377→  }
378→  return moves;
379→}
380→
381→function isSquareAttacked(row, col, byColor) {
382→  const enemy = byColor === 'white' ? 'black' : 'white';
383→  for (let r = 0; r < 8; r++) {
384→    for (let c = 0; c < 8; c++) {
385→      const p = boardState[r][c];
386→      if (!p || p.color !== enemy) continue;
387→      if (p.type === 'pawn') {
388→        const dir = p.color === 'white' ? -1 : 1;
389→        if (r + dir === row && (c - 1 === col || c + 1 === col)) return true;
390→      } else if (p.type === 'knight') {
391→        for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
392→          if (r + dr === row && c + dc === col) return true;
393→        }
394→      } else if (p.type === 'king') {
395→        if (Math.abs(r - row) <= 1 && Math.abs(c - col) <= 1) return true;
396→      } else {
397→        let dirs = [];
398→        if (p.type === 'rook' || p.type === 'queen') dirs.push([1,0],[-1,0],[0,1],[0,-1]);
399→        if (p.type === 'bishop' || p.type === 'queen') dirs.push([1,1],[1,-1],[-1,1],[-1,-1]);
400→        for (const [dr, dc] of dirs) {
401→          let sr = r + dr, sc = c + dc;
402→          while (sr >= 0 && sr < 8 && sc >= 0 && sc < 8) {
403→            if (sr === row && sc === col) return true;
404→            if (boardState[sr][sc]) break;
405→            sr += dr; sc += dc;
406→          }
407→        }
408→      }
409→    }
410→  }
411→  return false;
412→}
413→
414→function getValidMoves(piece, row, col) {
415→  const moves = [];
416→
417→  if (piece.type === 'pawn') {
418→    const dir = piece.color === 'white' ? -1 : 1;
419→    const startRow = piece.color === 'white' ? 6 : 1;
420→    if (inBounds(row + dir, col) && !boardState[row + dir][col]) {
421→      moves.push({ row: row + dir, col });
422→      if (row === startRow && !boardState[row + 2 * dir][col]) {
423→        moves.push({ row: row + 2 * dir, col });
424→      }
425→    }
426→    for (const dc of [-1, 1]) {
427→      const nr = row + dir, nc = col + dc;
428→      if (inBounds(nr, nc) && boardState[nr][nc] && boardState[nr][nc].color !== piece.color) {
429→        moves.push({ row: nr, col: nc });
430→      }
431→    }
432→    // En passant
433→    if (lastMove && lastMove.piece.type === 'pawn' &&
434→        Math.abs(lastMove.fromRow - lastMove.toRow) === 2 &&
435→        lastMove.toRow === row &&
436→        Math.abs(lastMove.toCol - col) === 1) {
437→      moves.push({ row: row + dir, col: lastMove.toCol, enPassant: true });
438→    }
439→  }
440→
441→  if (piece.type === 'rook' || piece.type === 'queen') {
442→    moves.push(...slidingMoves(row, col, [[1,0],[-1,0],[0,1],[0,-1]]));
443→  }
444→
445→  if (piece.type === 'bishop' || piece.type === 'queen') {
446→    moves.push(...slidingMoves(row, col, [[1,1],[1,-1],[-1,1],[-1,-1]]));
447→  }
448→
449→  if (piece.type === 'knight') {
450→    for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
451→      const nr = row + dr, nc = col + dc;
452→      if (inBounds(nr, nc)) {
453→        const target = boardState[nr][nc];
454→        if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
455→      }
456→    }
457→  }
458→
459→  if (piece.type === 'king') {
460→    for (let dr = -1; dr <= 1; dr++) {
461→      for (let dc = -1; dc <= 1; dc++) {
462→        if (dr === 0 && dc === 0) continue;
463→        const nr = row + dr, nc = col + dc;
464→        if (inBounds(nr, nc)) {
465→          const target = boardState[nr][nc];
466→          if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
467→        }
468→      }
469→    }
470→    // Castling
471→    const isWhite = piece.color === 'white';
472→    const kingMoved = isWhite ? hasMoved.whiteKing : hasMoved.blackKing;
473→    if (!kingMoved && !isKingInCheck(piece.color, boardState)) {
474→      const baseRow = isWhite ? 7 : 0;
475→      if (row === baseRow && col === 4) {
476→        // Kingside
477→        const rookHMoved = isWhite ? hasMoved.whiteRookH : hasMoved.blackRookH;
478→        if (!rookHMoved && boardState[baseRow][7] && boardState[baseRow][7].type === 'rook' &&
479→            !boardState[baseRow][5] && !boardState[baseRow][6]) {
480→          if (!isSquareAttacked(baseRow, 5, piece.color) && !isSquareAttacked(baseRow, 6, piece.color)) {
481→            moves.push({ row: baseRow, col: 6, castling: 'kingside' });
482→          }
483→        }
484→        // Queenside
485→        const rookAMoved = isWhite ? hasMoved.whiteRookA : hasMoved.blackRookA;
486→        if (!rookAMoved && boardState[baseRow][0] && boardState[baseRow][0].type === 'rook' &&
487→            !boardState[baseRow][1] && !boardState[baseRow][2] && !boardState[baseRow][3]) {
488→          if (!isSquareAttacked(baseRow, 2, piece.color) && !isSquareAttacked(baseRow, 3, piece.color)) {
489→            moves.push({ row: baseRow, col: 2, castling: 'queenside' });
490→          }
491→        }
492→      }
493→    }
494→  }
495→
496→  return moves;
497→}
498→
499→function findKing(color) {
500→  for (let r = 0; r < 8; r++) {
501→    for (let c = 0; c < 8; c++) {
502→      const p = boardState[r][c];
503→      if (p && p.type === 'king' && p.color === color) return { row: r, col: c };
504→    }
505→  }
506→  return null;
507→}
508→
509→function isKingInCheck(color, board) {
510→  let kingRow = -1, kingCol = -1;
511→  for (let r = 0; r < 8; r++) {
512→    for (let c = 0; c < 8; c++) {
513→      const p = board[r][c];
514→      if (p && p.type === 'king' && p.color === color) {
515→        kingRow = r; kingCol = c; break;
516→      }
517→    }
518→    if (kingRow >= 0) break;
519→  }
520→
521→  const enemy = color === 'white' ? 'black' : 'white';
522→
523→  for (let r = 0; r < 8; r++) {
524→    for (let c = 0; c < 8; c++) {
525→      const p = board[r][c];
526→      if (!p || p.color !== enemy) continue;
527→
528→      if (p.type === 'pawn') {
529→        const dir = p.color === 'white' ? -1 : 1;
530→        if (r + dir === kingRow && (c - 1 === kingCol || c + 1 === kingCol)) return true;
531→      } else if (p.type === 'knight') {
532→        for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
533→          if (r + dr === kingRow && c + dc === kingCol) return true;
534→        }
535→      } else if (p.type === 'king') {
536→        if (Math.abs(r - kingRow) <= 1 && Math.abs(c - kingCol) <= 1) return true;
537→      } else {
538→        let dirs = [];
539→        if (p.type === 'rook' || p.type === 'queen') dirs.push([1,0],[-1,0],[0,1],[0,-1]);
540→        if (p.type === 'bishop' || p.type === 'queen') dirs.push([1,1],[1,-1],[-1,1],[-1,-1]);
541→        for (const [dr, dc] of dirs) {
542→          let sr = r + dr, sc = c + dc;
543→          while (sr >= 0 && sr < 8 && sc >= 0 && sc < 8) {
544→            if (sr === kingRow && sc === kingCol) return true;
545→            if (board[sr][sc]) break;
546→            sr += dr; sc += dc;
547→          }
548→        }
549→      }
550→    }
551→  }
552→  return false;
553→}
554→
555→function getLegalMoves(piece, row, col) {
556→  const pseudo = getValidMoves(piece, row, col);
557→  return pseudo.filter(m => {
558→    const saved = boardState[m.row][m.col];
559→    boardState[m.row][m.col] = boardState[row][col];
560→    boardState[row][col] = null;
561→
562→    // For en passant, also remove the captured pawn
563→    let epCaptured = null;
564→    if (m.enPassant) {
565→      epCaptured = boardState[row][m.col];
566→      boardState[row][m.col] = null;
567→    }
568→
569→    const inCheck = isKingInCheck(piece.color, boardState);
570→
571→    // Undo
572→    boardState[row][col] = boardState[m.row][m.col];
573→    boardState[m.row][m.col] = saved;
574→    if (m.enPassant) boardState[row][m.col] = epCaptured;
575→
576→    return !inCheck;
577→  });
578→}
579→
580→function hasAnyLegalMoves(color) {
581→  for (let r = 0; r < 8; r++) {
582→    for (let c = 0; c < 8; c++) {
583→      const p = boardState[r][c];
584→      if (p && p.color === color && getLegalMoves(p, r, c).length > 0) return true;
585→    }
586→  }
587→  return false;
588→}
589→
590→function getSquareEl(row, col) {
